ALTER TABLE products
  ADD COLUMN IF NOT EXISTS category TEXT,
  ADD COLUMN IF NOT EXISTS product_line TEXT,
  ADD COLUMN IF NOT EXISTS base TEXT,
  ADD COLUMN IF NOT EXISTS sheen TEXT,
  ADD COLUMN IF NOT EXISTS volume_litres NUMERIC(6,2),
  ADD COLUMN IF NOT EXISTS price NUMERIC(10,2),
  ADD COLUMN IF NOT EXISTS rrp_price NUMERIC(10,2),
  ADD COLUMN IF NOT EXISTS product_code TEXT,
  ADD COLUMN IF NOT EXISTS source_url TEXT;

CREATE INDEX IF NOT EXISTS idx_products_material_search
  ON products USING gin(to_tsvector('english', coalesce(name, '') || ' ' || coalesce(manufacturer, '') || ' ' || coalesce(type, '') || ' ' || coalesce(category, '') || ' ' || coalesce(product_line, '') || ' ' || coalesce(base, '') || ' ' || coalesce(sheen, '') || ' ' || coalesce(product_code, '')));

