ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  manufacturer = EXCLUDED.manufacturer,
  type = EXCLUDED.type,
  unit = EXCLUDED.unit,
  market_price = EXCLUDED.market_price,
  actual_price = EXCLUDED.actual_price,
  color_code = EXCLUDED.color_code,
  active = EXCLUDED.active,
  category = EXCLUDED.category,
  product_line = EXCLUDED.product_line,
  base = EXCLUDED.base,
  sheen = EXCLUDED.sheen,
  volume_litres = EXCLUDED.volume_litres,
  price = EXCLUDED.price,
  rrp_price = EXCLUDED.rrp_price,
  product_code = EXCLUDED.product_code,
  source_url = EXCLUDED.source_url,
  updated_at = now();

UPDATE products
SET
  market_price = COALESCE(rrp_price, price, market_price),
  actual_price = COALESCE(rrp_price, price, market_price),
  updated_at = now()
WHERE manufacturer = 'Dulux'
  AND source_url LIKE 'https://www.inspirationspaint.com.au/%';
